def compute_sha256(file_path: str) -> str:
    """Compute SHA-256 hash of a file."""
    sha256_hash = hashlib.sha256()
    with open(file_path, 'rb') as f:
        for chunk in iter(lambda: f.read(8192), b''):
            sha256_hash.update(chunk)
    return sha256_hash.hexdigest()


def validate_onnx_structure(file_path: str) -> bool:
    """
    Perform basic structural validation of an ONNX file.
    Checks magic bytes and basic protobuf structure without full deserialization.
    """
    try:
        with open(file_path, 'rb') as f:
            # ONNX files are protobuf - check it's not a pickle or other dangerous format
            header = f.read(32)

            # Check it's not a Python pickle (pickle opcodes start with specific bytes)
            pickle_markers = [b'\x80\x02', b'\x80\x03', b'\x80\x04', b'\x80\x05', b'cos\n', b'c__builtin__']
            for marker in pickle_markers:
                if header.startswith(marker):
                    logger.error("File appears to be a Python pickle, not ONNX: %s", file_path)
                    return False

            # Check it's not a PyTorch file (ZIP with pickle inside)
            if header[:2] == b'PK':
                logger.error("File appears to be a ZIP/PyTorch archive, not ONNX: %s", file_path)
                return False

            # Check it's not a numpy file
            if header[:6] == b'\x93NUMPY':
                logger.error("File appears to be a NumPy file, not ONNX: %s", file_path)
                return False

            # Basic protobuf field tag check - ONNX ModelProto starts with field 1 (ir_version)
            # which is a varint, so the tag byte should be 0x08
            f.seek(0)
            first_byte = f.read(1)
            if not first_byte:
                logger.error("Empty file: %s", file_path)
                return False

            # Protobuf wire type check - first field should have valid wire type
            tag = first_byte[0]
            wire_type = tag & 0x07
            if wire_type > 5:
                logger.error("Invalid protobuf wire type in file: %s", file_path)
                return False

        # Check file size is reasonable (not zero, not suspiciously tiny)
        file_size = os.path.getsize(file_path)
        if file_size < 16:
            logger.error("File too small to be a valid ONNX model: %s (%d bytes)", file_path, file_size)
            return False

        return True
    except Exception as e:
        logger.error("Structural validation failed for %s: %s", file_path, e)
        return False


def validate_file_path(path: str) -> str:
    """Validate and sanitize file paths to prevent path traversal."""
    # Resolve to absolute path and check for traversal
    resolved = os.path.realpath(path)

    # Ensure no null bytes
    if '\x00' in path:
        raise ValueError("Null bytes detected in path")

    # Check for suspicious path components
    parts = Path(path).parts
    for part in parts:
        if part in ('..', '.'):
            continue  # os.path.realpath handles these
        if part.startswith('-'):
            raise ValueError(f"Suspicious path component: {part}")

    return resolved


class SecureModelLoader:
    """
    Secure ML model loader that fetches models from cloud storage
    with integrity verification and format validation.

    Security measures:
    - SHA-256 checksum verification against a trusted manifest
    - File format validation (rejects pickle, PyTorch, numpy formats)
    - ONNX-only loading (no arbitrary code execution via pickle)
    - Path traversal prevention
    - Secure temporary file handling
    - Model size limits
    - Restricted ONNX runtime session options
    """

    # 10 GB max model size
    MAX_MODEL_SIZE = 10 * 1024 * 1024 * 1024

    def __init__(self):
        self.model_path = os.environ.get('MODEL_PATH')
        if not self.model_path:
            raise EnvironmentError("MODEL_PATH environment variable must be set")

        self.model_key = os.environ.get('MODEL_KEY', 'default')

        manifest_path = os.environ.get('MODEL_MANIFEST_PATH')
        if not manifest_path:
            raise EnvironmentError(
                "MODEL_MANIFEST_PATH environment variable must be set. "
                "A trusted manifest with SHA-256 checksums is required."
            )
        self.manifest = ModelManifest(manifest_path)

        self.local_cache_dir = os.environ.get('MODEL_CACHE_DIR', '/tmp/model_cache')
        os.makedirs(self.local_cache_dir, mode=0o700, exist_ok=True)

        self.s3_client = self._create_s3_client()
        self.session: Optional[ort.InferenceSession] = None
        self.current_version: Optional[str] = None

    def _create_s3_client(self):
        """Create S3 client with appropriate configuration."""
        return boto3.client(
            's3',
            config=boto3.session.Config(
                signature_version='s3v4',
                s3={'addressing_style': 'virtual'}
            )
        )

    def _parse_s3_path(self, path: str):
        """Parse s3://bucket/key format."""
        if not path.startswith('s3://'):
            raise ValueError(f"Invalid S3 path format: {path}")
        parts = path[5:].split('/', 1)
        if len(parts) != 2:
            raise ValueError(f"Invalid S3 path format: {path}")
        return parts[0], parts[1]

    def _get_latest_version(self) -> str:
        """Get the latest approved model version from the manifest."""
        version = self.manifest.get_latest_version(self.model_key)
        if not version:
            raise ValueError(
                f"No approved version found for model '{self.model_key}' in manifest"
            )
        logger.info("Latest approved version for '%s': %s", self.model_key, version)
        return version

    def _download_model(self, version: str) -> str:
        """Download model from S3 to a secure temporary location."""
        bucket, key_prefix = self._parse_s3_path(self.model_path)

        # Construct the versioned key
        model_key = f"{key_prefix}/{version}/model.onnx"

        # Validate the allowed format
        allowed_format = self.manifest.get_allowed_format(self.model_key)
        if allowed_format != "onnx":
            raise ModelIntegrityError(
                f"Only ONNX format is supported for security. Got: {allowed_format}"
            )

        # Check object size before downloading
        try:
            head = self.s3_client.head_object(Bucket=bucket, Key=model_key)
            content_length = head.get('ContentLength', 0)
            if content_length > self.MAX_MODEL_SIZE:
                raise ModelIntegrityError(
                    f"Model size {content_length} exceeds maximum allowed size {self.MAX_MODEL_SIZE}"
                )
            if content_length == 0:
                raise ModelIntegrityError("Model file is empty")
        except self.s3_client.exceptions.ClientError as e:
            raise FileNotFoundError(f"Model not found at s3://{bucket}/{model_key}: {e}")

        # Download to a secure temporary file
