    def predict(self, input_data: Dict[str, Any]) -> Any:
        """Run inference on the loaded model."""
        if self.session is None:
            raise RuntimeError("No model loaded. Call load_latest_model() first.")

        input_names = [inp.name for inp in self.session.get_inputs()]
        output_names = [out.name for out in self.session.get_outputs()]

        feed = {name: input_data[name] for name in input_names if name in input_data}

        results = self.session.run(output_names, feed)
        return dict(zip(output_names, results))


