    try:
        loader = SecureModelLoader()
        session = loader.load_latest_model()

        logger.info(
            "Model loaded successfully. Version: %s, Inputs: %s, Outputs: %s",
            loader.current_version,
            [inp.name for inp in session.get_inputs()],
            [out.name for out in session.get_outputs()]
        )

        # Keep service running (in production, this would be an HTTP server)
        logger.info("Inference service ready")

    except ModelIntegrityError as e:
        logger.critical("SECURITY: Model integrity verification failed: %s", e)
        sys.exit(2)
    except FileNotFoundError as e:
        logger.error("Model or manifest not found: %s", e)
